```class Solution {
public:
    bool isPossible(vector<int>& nums) {
        int n = nums.size();
        for (int i = 0; i < n - 2; i++) {
            for (int j = i + 1; j < n - 1; j++) {
                if (nums[j] - nums[i] != 1 || nums[j+1] - nums[j] != 1) {
                    return false;
                }
            }
        }
        return true;
    }
};
